dtsPropsFor.Button:
/** Визуальный вариант. */
variant?: "default" | "outline" | "secondary" | "ghost" | "destructive" | "link";
/** Размер; icon* — квадратная кнопка только под иконку. */
size?: "default" | "xs" | "sm" | "lg" | "icon" | "icon-xs" | "icon-sm" | "icon-lg";
/** Рендерить как дочерний элемент (Radix Slot) вместо <button>. */
asChild?: boolean;
children?: React.ReactNode;
className?: string;
disabled?: boolean;
type?: "button" | "submit" | "reset";
onClick?: React.MouseEventHandler<HTMLButtonElement>;
"aria-label"?: string;

dtsPropsFor.GlitchText:
/** Текст «разряда» («системный регистр»). */
text: string;
className?: string;
/** Запустить анимацию разряда (по умолчанию true). На статичном превью при false — чистый текст. */
play?: boolean;
onDone?: () => void;

dtsPropsFor.StoryOpening:
/** Текст первой строки («первая строка как событие»). */
text: string;
/** Источник детерминированного варианта, если variant не задан. */
slug?: string;
/** Шаблон кинетики зачина. */
variant?: "rise" | "cascade" | "glitch";
className?: string;
onDone?: () => void;

dtsPropsFor.WorkshopCard:
/** Запись ленты «Мастерской». */
entry: {
  slug: string;
  title: string;
  kind: "fragment" | "draft" | "note" | "illustration";
  date: string;
  summary?: string;
  themes?: string[];
  image?: string;
  imageWidth?: number;
  imageHeight?: number;
  imageAlt?: string;
  published?: boolean;
  body: string;
};

dtsPropsFor.IllustrationPlate:
/** Иллюстрация-плашка (editorial, «с воздухом»). */
illustration: {
  src: string;
  width: number;
  height: number;
  alt: string;
  artist?: string;
};
/** Приоритетная загрузка (LCP). */
priority?: boolean;

dtsPropsFor.WheelIndex:
/** Граф «Колеса»: узлы (темы/рассказы) + рёбра членства «рассказ ↔ тема». */
graph: {
  nodes: Array<{ id: string; kind: "theme" | "story"; label: string; book?: string; firstLine?: string }>;
  links: Array<{ source: string; target: string; weight: number }>;
};

dtsPropsFor.EmptyState:
/** Реплика «одержимой системы» (сериф, «душа»). По умолчанию — канон из systemVoice. */
line?: string;
/** Моно-приписка под репликой («система»). */
note?: string;

dtsPropsFor.Reveal:
/** Что проявляем при входе в кадр. */
children?: React.ReactNode;
className?: string;
/** Начальный сдвиг вниз, px (по умолчанию 14). */
y?: number;
/** Если задан — стаггер прямых детей, сек (напр. 0.06). */
stagger?: number;
/** ScrollTrigger start (по умолчанию "top 85%"). */
start?: string;
/** Проявить один раз и не прятать обратно (по умолчанию true). */
once?: boolean;

dtsPropsFor.FogReveal:
/** Что проявляем «из тумана». */
children?: React.ReactNode;
className?: string;
/** Стартовое размытие, px (по умолчанию 22). */
blur?: number;
/** ScrollTrigger start (по умолчанию "top 80%"). */
start?: string;

dtsPropsFor.AccentLine:
className?: string;
/** ScrollTrigger start (по умолчанию "top 85%"). */
start?: string;

dtsPropsFor.AnchorPlate:
/** Источник изображения (обычный <img> в бандле — реальный src или data-URI). */
src: string;
/** Интринсик-размеры изображения — задают пропорцию плашки (высота фикс. 84px). */
width: number;
height: number;
/** Позиция центра плашки в процентах родителя с position:relative (transform -50%,-50%). */
left: string;
top: string;
/** Тема горит — полная плотность (иначе покой 0.62). */
lit: boolean;
/** Внимание на другом узле — глушится до 0.3. */
dimmed: boolean;
/** Лёгкий подъём паспарту под живым вниманием (только при no-preference). */
lift: boolean;
